<?php
/**
 * Controller for the Post Block.
 *
 * @since 1.0.0
 *
 * @package Spectra\Blocks\Post
 */

use SpectraBlocks\Helpers\BlockAttributes;

// Retrieve block attributes.
$layout_type     = $attributes['layoutType'] ?? 'grid';
$slides_per_view = $attributes['slidesPerView'] ?? 3;
$space_between   = $attributes['spaceBetween'] ?? 30;
$equal_height    = $attributes['equalHeight'] ?? true;

// Get Query ID (generated by editor via useInstanceId for multi-block support).
$query_id = ( isset( $attributes['queryId'] ) && '' !== $attributes['queryId'] ) ? $attributes['queryId'] : '';

// Generate page key for query-specific pagination (e.g., query-abc123-page).
$page_key = ( '' !== $query_id ) ? "query-{$query_id}-page" : 'page';

// Get query parameters from nested query object.
$query_obj         = $attributes['query'] ?? array();
$query_post_type   = $query_obj['postType'] ?? 'post';
$query_per_page    = $query_obj['perPage'] ?? $attributes['postsToShow'] ?? 6;
$query_order       = $query_obj['order'] ?? 'desc';
$query_order_by    = $query_obj['orderBy'] ?? 'date';
$author            = $query_obj['author'] ?? array();
$query_search      = $query_obj['search'] ?? '';
$excluded_post_ids = $query_obj['exclude'] ?? array();
$sticky            = $query_obj['sticky'] ?? '';
$offset            = $query_obj['offset'] ?? 0;
$exclude_current   = $query_obj['excludeCurrentPost'] ?? false;
$tax_query_obj     = $query_obj['taxQuery'] ?? null;

if ( $exclude_current ) {
	$excluded_post_ids[] = get_the_ID();
}

// Pagination settings.
$pagination_type       = $attributes['paginationType'] ?? 'none';
$pagination_event_type = $attributes['paginationEventType'] ?? 'button';
$pagination_prev       = $attributes['paginationPrevLabel'] ?? __( '« Previous', 'spectra-blocks' );
$pagination_next       = $attributes['paginationNextLabel'] ?? __( 'Next »', 'spectra-blocks' );
$pagination_button     = $attributes['paginationButtonText'] ?? __( 'Load More', 'spectra-blocks' );
$pagination_loading    = $attributes['paginationLoadingText'] ?? __( 'Loading...', 'spectra-blocks' );
$pagination_alignment  = $attributes['paginationAlignment'] ?? 'center';
$pagination_layout     = $attributes['paginationLayout'] ?? 'filled';

// Carousel settings.
$loop           = $attributes['loop'] ?? true;
$speed          = $attributes['speed'] ?? 500;
$autoplay       = $attributes['autoplay'] ?? true;
$autoplay_speed = $attributes['autoplaySpeed'] ?? 2000;
$pause_on_hover = $attributes['autoplayPauseOnHover'] ?? true;
$navigation     = $attributes['navigation'] ?? true;
$pagination     = $attributes['pagination'] ?? true;

// Retrieve responsive controls.
$attr_responsive_controls = $attributes['responsiveControls'] ?? array();

// Helper to get responsive value with proper inheritance/fallback.
// Fallback order: sm → md → lg → default, md → lg → default, lg → default.
$get_responsive_value = function ( $device, $key, $fallback ) use ( $attr_responsive_controls ) {
	// Define fallback order for each device.
	$fallback_order = array(
		'sm' => array( 'sm', 'md', 'lg' ), // Mobile: try mobile → tablet → desktop.
		'md' => array( 'md', 'lg' ),       // Tablet: try tablet → desktop.
		'lg' => array( 'lg' ),             // Desktop: only desktop.
	);

	// Get the fallback chain for this device.
	$devices_to_check = $fallback_order[ $device ] ?? array( $device );

	// Check each device in the fallback chain.
	foreach ( $devices_to_check as $check_device ) {
		if ( isset( $attr_responsive_controls[ $check_device ][ $key ] ) ) {
			return $attr_responsive_controls[ $check_device ][ $key ];
		}
	}

	// No value found in any fallback, return fallback.
	return $fallback;
};

// Get query metadata if available (set by post-template block during inner block rendering).
global $spectra_current_query;

// Build Swiper config for carousel layout.
$swiper_config = array();
if ( 'carousel' === $layout_type ) {
	$sm_slides_per_view = $get_responsive_value( 'sm', 'slidesPerView', $slides_per_view );
	$md_slides_per_view = $get_responsive_value( 'md', 'slidesPerView', $slides_per_view );
	$lg_slides_per_view = $get_responsive_value( 'lg', 'slidesPerView', $slides_per_view );

	$sm_space_between = $get_responsive_value( 'sm', 'spaceBetween', $space_between );
	$md_space_between = $get_responsive_value( 'md', 'spaceBetween', $space_between );
	$lg_space_between = $get_responsive_value( 'lg', 'spaceBetween', $space_between );

	// Auto-disable loop if insufficient posts to prevent empty slides.
	// Loop needs at least 3 full groups for smooth operation.
	$should_enable_loop = $loop;
	if ( $loop && ! empty( $spectra_current_query ) ) {
		$total_posts         = $spectra_current_query->found_posts;
		$max_slides_per_view = max( $lg_slides_per_view, $md_slides_per_view, $sm_slides_per_view );
		$min_posts_for_loop  = $max_slides_per_view * 3; // Need at least 3 full pages.

		if ( $total_posts < $min_posts_for_loop ) {
			$should_enable_loop = false;
		}
	}

	$swiper_config = array(
		'slidesPerView'        => $lg_slides_per_view,
		'slidesPerGroup'       => 1,
		'spaceBetween'         => $lg_space_between,
		'loop'                 => $should_enable_loop,
		'speed'                => $speed,
		'watchOverflow'        => true,
		'observer'             => true,
		'observeParents'       => true,
		'observeSlideChildren' => true,
		'autoHeight'           => ! $equal_height,
		'autoplay'             => $autoplay ? array(
			'delay'                => $autoplay_speed,
			'disableOnInteraction' => false,
			'pauseOnMouseEnter'    => $pause_on_hover,
		) : false,
		'navigation'           => $navigation,
		'pagination'           => $pagination,
		'breakpoints'          => array(
			'0'    => array(
				'slidesPerView'  => $sm_slides_per_view,
				'slidesPerGroup' => 1,
				'spaceBetween'   => $sm_space_between,
			),
			'768'  => array(
				'slidesPerView'  => $md_slides_per_view,
				'slidesPerGroup' => 1,
				'spaceBetween'   => $md_space_between,
			),
			'1024' => array(
				'slidesPerView'  => $lg_slides_per_view,
				'slidesPerGroup' => 1,
				'spaceBetween'   => $lg_space_between,
			),
		),
	);
}

// Read current page from query-specific URL parameter.
// phpcs:ignore WordPress.Security.NonceVerification.Recommended
$current_page = isset( $_GET[ $page_key ] ) ? max( 1, absint( $_GET[ $page_key ] ) ) : 1;
$total_pages  = 0;
$has_more     = false;

if ( ! empty( $spectra_current_query ) ) {
	$total_pages = $spectra_current_query->max_num_pages;
	$has_more    = $current_page < $total_pages;
}

// Build context for Interactivity API.
$post_context = array(
	'queryId'        => $query_id,
	'pageKey'        => $page_key,
	'layoutType'     => $layout_type,
	'paginationType' => $pagination_type,
	'isLoading'      => false,
	'currentPage'    => $current_page,
	'totalPages'     => $total_pages,
	'hasMore'        => $has_more,
);

// Custom classes.
$custom_classes = array(
	'spectra-post-layout-' . $layout_type,
);

if ( $equal_height ) {
	$custom_classes[] = 'spectra-post-equal-height';
}

if ( 'none' !== $pagination_type ) {
	$custom_classes[] = 'spectra-pagination-align-' . $pagination_alignment;
	if ( 'standard' === $pagination_type ) {
		$custom_classes[] = 'spectra-pagination-layout-' . $pagination_layout;
	}
}

// Logic to determine initial visibility of carousel arrows (responsive).
$arrow_opacity_lg = 0;
$arrow_opacity_md = 0;
$arrow_opacity_sm = 0;

if ( 'carousel' === $layout_type && $navigation && ! empty( $spectra_current_query ) ) {
	$total_posts = $spectra_current_query->found_posts;
	if ( isset( $spectra_current_query->post_count ) && $spectra_current_query->post_count < $total_posts ) {
		$total_posts = $spectra_current_query->post_count;
	}

	$arrow_opacity_lg = ( $total_posts > $lg_slides_per_view ) ? 1 : 0;
	$arrow_opacity_md = ( $total_posts > $md_slides_per_view ) ? 1 : 0;
	$arrow_opacity_sm = ( $total_posts > $sm_slides_per_view ) ? 1 : 0;

}

// Style and class configurations for carousel and pagination options.
$config = array(
	array(
		'key'     => 'arrowColor',
		'css_var' => '--spectra-carousel-arrow-color',
	),
	array(
		'key'     => 'arrowBackgroundColor',
		'css_var' => '--spectra-carousel-arrow-bg-color',
	),
	array(
		'key'     => 'dotColor',
		'css_var' => '--spectra-carousel-dot-color',
	),
	array(
		'key'     => 'paginationColor',
		'css_var' => '--spectra-pagination-color',
	),
	array(
		'key'     => 'paginationBackgroundColor',
		'css_var' => '--spectra-pagination-bg-color',
	),
	array(
		'key'     => 'paginationHoverColor',
		'css_var' => '--spectra-pagination-color-hover',
	),
	array(
		'key'     => 'paginationBackgroundHoverColor',
		'css_var' => '--spectra-pagination-bg-color-hover',
	),
	array(
		'key'     => 'paginationActiveColor',
		'css_var' => '--spectra-pagination-color-active',
	),
	array(
		'key'     => 'paginationBackgroundActiveColor',
		'css_var' => '--spectra-pagination-bg-color-active',
	),
);

// Prepare custom styles for responsive layout (injected as inline vars).
$custom_style = array();
if ( 'carousel' === $layout_type ) {
	$custom_style = array(
		'--spectra-carousel-slides-lg' => (string) $lg_slides_per_view,
		'--spectra-carousel-gap-lg'    => $lg_space_between . 'px',
		'--spectra-arrow-opacity-lg'   => (string) $arrow_opacity_lg,

		'--spectra-carousel-slides-md' => (string) $md_slides_per_view,
		'--spectra-carousel-gap-md'    => $md_space_between . 'px',
		'--spectra-arrow-opacity-md'   => (string) $arrow_opacity_md,

		'--spectra-carousel-slides-sm' => (string) $sm_slides_per_view,
		'--spectra-carousel-gap-sm'    => $sm_space_between . 'px',
		'--spectra-arrow-opacity-sm'   => (string) $arrow_opacity_sm,
	);
}

// Get wrapper attributes.
$custom_classes[] = 'spectra-post-carousel-' . $query_id;

$wrapper_attributes = BlockAttributes::get_wrapper_attributes( $attributes, $config, array(), $custom_classes, $custom_style );

return 'file:./view.php';
